### Step 7: `src/lib/Selector.svelte.spec.ts`

Tests run under the `client` Vitest project (browser/Playwright). The file extension `.svelte.spec.ts` matches the include pattern `src/**/*.svelte.{test,spec}.{js,ts}`. Uses `vitest-browser-svelte`'s `render` and Vitest's locator/`expect.element` API with retry-ability.

Important: the spec must import from `vitest-browser-svelte` (not `@testing-library/svelte`, which is not installed). The locator API (`screen.getByRole`, `screen.getByText`, `.click()`) returns Playwright-style locators, and assertions use `expect.element(...).toBeVisible()` which is retry-aware.

The test must set up state before each test. Because `appState` is a singleton module export, tests share state. Two options:
1. Reset `appState.currentlySelected = 0` in `beforeEach`
2. Don't mutate in tests — only assert

Option 1 is cleaner. The `beforeEach` also handles component cleanup (handled by `vitest-browser-svelte` internally already).

```typescript
// src/lib/Selector.svelte.spec.ts
import { render } from 'vitest-browser-svelte';
import { describe, it, expect, beforeEach } from 'vitest';
import Selector from './Selector.svelte';
import { appState } from './state.svelte';

describe('Selector', () => {
    beforeEach(() => {
        // Reset to known state between tests
        appState.currentlySelected = 0;
    });

    it('renders all chats by name', async () => {
        const screen = render(Selector);

        for (const chat of appState.chats) {
            await expect.element(screen.getByText(chat.name)).toBeVisible();
        }
    });

    it('shows a status indicator for each chat', async () => {
        const screen = render(Selector);

        // Each chat row should contain a status dot element
        const dots = screen.container.querySelectorAll('.status-dot');
        expect(dots.length).toBe(appState.chats.length);
    });

    it('highlights the currently selected chat', async () => {
        const screen = render(Selector);

        // The first chat row should have the 'selected' class
        const rows = screen.container.querySelectorAll('.chat-row');
        expect(rows[0].classList.contains('selected')).toBe(true);
        expect(rows[1].classList.contains('selected')).toBe(false);
    });

    it('clicking a chat updates currentlySelected', async () => {
        const screen = render(Selector);

        const secondChatName = appState.chats[1].name;
        await screen.getByText(secondChatName).click();

        expect(appState.currentlySelected).toBe(1);
    });

    it('selected class moves to the clicked chat', async () => {
        const screen = render(Selector);

        const secondChatName = appState.chats[1].name;
        await screen.getByText(secondChatName).click();

        const rows = screen.container.querySelectorAll('.chat-row');
        await expect.element(screen.getByText(secondChatName)).toBeVisible();
        // The second row now has selected class, first does not
        expect(rows[0].classList.contains('selected')).toBe(false);
        expect(rows[1].classList.contains('selected')).toBe(true);
    });

    it('shows last message preview for chats that have messages', async () => {
        const screen = render(Selector);

        // Jordan's last message text should appear somewhere
        const jordanLastMsg = appState.chats[1].messages.at(-1)!.text;
        await expect.element(screen.getByText(jordanLastMsg)).toBeVisible();
    });

    it('shows placeholder for chats with no messages', async () => {
        const screen = render(Selector);

        // Claudia (index 0) and Riley (index 3) have no messages
        const empties = screen.container.querySelectorAll('.chat-preview.empty');
        expect(empties.length).toBeGreaterThan(0);
    });
});
